/**
 * Code: Build Simulate Payin Payload
 * 
 * Menyusun request body untuk simulasi transaksi payin di sandbox.
 * 
 * Input:
 *   - Webhook (GET) -> query.payin_id, query.transaction_status
 * 
 * Output:
 *   - timestamp: ISO timestamp untuk header request
 *   - signaturePayload: string payload yang akan di-sign dengan HMAC-SHA256
 *   - body: object request body untuk POST /v1/simulator/transaction
 * 
 * Status yang didukung: SUCCESS, FAILED, EXPIRED
 */

const method = "POST"
const uri = "/v1/simulator/transaction"
const timestamp = new Date().toISOString()

// Susun body simulasi dengan status yang dipilih dari query parameter
const body = {
    transactionId: $input.first().json.query.payin_id,
    transactionCategory: "payins",
    transactionStatus: $input.first().json.query.transaction_status,
}

// Susun signature payload sesuai format XenithPay
const bodyString = JSON.stringify(body)
const signaturePayload = `${method}\n${uri}\n${timestamp}\n${bodyString}`;

return {timestamp, signaturePayload, body};

const ref = $input.first().json.reference_code;

return [{
  code: "REFERENCE_ALREADY_EXISTS",
  message: `Reference code ${ref} already exists`
}];

