      const formattedAmount = new Intl.NumberFormat('id-ID', {
        style: 'currency',
        currency: 'IDR',
        minimumFractionDigits: 0
      }).format(amount);

      amountEl.innerText = formattedAmount;
    } else {
      let dots = 0;
      setInterval(() => {
        dots = (dots + 1) % 4;
        amountEl.innerText = "Menunggu pembayaran" + ".".repeat(dots);
      }, 500);
    }

    // 🔥 FORMAT TIME
    const date = new Date(updatedTime);

    document.getElementById("time").innerText = date.toLocaleString('id-ID', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit'
    });

    // 🔥 AUTO RELOAD
    if (status === "PENDING") {
      setInterval(() => {
        location.reload();
      }, 5000);
    }
  </script>

